// providers/native/src/code-synthesis.ts
import { CodeSynthesisCapability } from '@mycodexvantaos/capabilities';

export class NativeCodeSynthesis implements CodeSynthesisCapability {
  capability = 'code-synthesis' as const;
  source = 'native' as const;

  async healthCheck() { return true; }

  async generate({ prompt, context }: SynthesisOptions): Promise<SynthesisResult> {
    // 本地规则：模板匹配 + AST 变换（不调用任何 API）
    const suggestion = this.applyLocalTemplates(prompt, context);
    return { code: suggestion, confidence: 0.6, provider: 'native' };
  }

  private applyLocalTemplates(prompt: string, context: any): string {
    // 简化实现：基于关键词的代码片段生成
    if (prompt.includes('react component')) return `const Component = () => <div>...</div>`;
    if (prompt.includes('api route')) return `app.get('/api/...', (req, res) => {})`;
    return `// 无法生成高级代码，请连接外部 AI 获得更好结果`;
  }
}
```

