  }
}
```

4. 实现 Hybrid Provider（带降级）

```typescript
// providers/hybrid/src/code-synthesis.ts
export class HybridCodeSynthesis implements CodeSynthesisCapability {
  source = 'hybrid';
  constructor(private external: ExternalCodeSynthesis, private native: NativeCodeSynthesis) {}

  async generate(options: SynthesisOptions): Promise<SynthesisResult> {
    try {
      const result = await this.external.generate(options);
      return result;
    } catch (err) {
      console.warn('External AI failed, falling back to native', err);
      const fallback = await this.native.generate(options);
      return { ...fallback, fallbackTriggered: true };
    }
  }
}
