import { MYCODEXVANTAOS_CORE_RUNTIME_MODE } from './env';

export function getCodeSynthesisProvider(): CodeSynthesisCapability {
  const mode = process.env.MYCODEXVANTAOS_CORE_RUNTIME_MODE || 'auto';

  const hasApiKey = !!process.env.ANTHROPIC_API_KEY;
  const external = hasApiKey ? new ExternalCodeSynthesis(process.env.ANTHROPIC_API_KEY) : null;
  const native = new NativeCodeSynthesis();

  switch (mode) {
    case 'native':
      return native;
    case 'connected':
      if (!external) throw new Error('Connected mode requires API key');
      return external;
    case 'hybrid':
      return external ? new HybridCodeSynthesis(external, native) : native;
    case 'auto':
      return external ? new HybridCodeSynthesis(external, native) : native;
    default:
      return native;
  }
}
```

